Quy Tắc Cập Nhật Biến:
  # =================================================================
  # [LUẬT LÕI - CẤM TUYỆT ĐỐI VI PHẠM]
  # =================================================================
  General_Operations:
    check:
      - [CẤM LỆNH ẢO]: CHỈ ĐƯỢC PHÉP sử dụng các JSON Patch operation chuẩn: 'add', 'replace', 'remove', 'move', 'copy'. TUYỆT ĐỐI CẤM sử dụng các lệnh không tồn tại như 'update', 'modify'.
      - [CẤM BỊA ĐƯỜNG DẪN]: Chỉ được cập nhật các biến tồn tại trong Initvar gốc. Tuyệt đối không tự ý đẻ thêm biến mới (Ví dụ: Cấm tạo '/tamer/currencies/luck'). Để cộng/trừ số liệu, AI phải tự tính toán kết quả cuối cùng và dùng lệnh 'replace' (hoặc 'delta' nếu được hỗ trợ).
      - [LOGIC MÔ TẢ]: Khi thêm vật phẩm hoặc kỹ năng mới, BẮT BUỘC phải điền trường 'description' để mô tả ngoại hình, công dụng hoặc hiệu ứng.
      - [ĐỊNH DẠNG OBJECT]: Khi thêm mới item, skill hoặc NPC, phải dùng cấu trúc Object đầy đủ như định nghĩa trong 'schemamoi.yaml' (VD: Skill phải có cost, cooldown, cast_time; Item phải có uid, rank_quality, stats_modifiers).

  # =================================================================
  # [1] SỦNG THÚ (BEAST ROSTER)
  # =================================================================
  beast_roster.{Index}:
    type: |-
      {
        id: string; // VD: "pet_01"
        name: string;
        species_name: string; // VD: "Đường (Bọ Ngựa - Biến Dị)"

        // [NEW V5] Lore Chủng tộc & Huyết mạch
        species_info: {
            name: string;
            type_class: string;
            description_lore: string;
            biological_features: string[];
        };
        bloodline_info: {
            name: string;
            description_lore: string;
            rank_quality: string;
            stats_modifiers: object; // { STR: 500, HP_max: 2000... }
        };

        // [NEW] Hệ thống Đa Hệ & Tổ Hợp
        elemental_affinity: {
            base_elements: Array<{ type: string; description: string; dominance: number }>;
            combined_effect: { name: string; description: string; stability: number };
            weaknesses: string[];
        };
        // Alias cũ (Giữ tương thích)
        attribute: string; 

        gender: 'Đực' | 'Cái' | 'Vô Tính';
        personality: string;
        age: number; // [NEW] Tuổi thọ

        rank_tier: string; // Cấp bậc (Man Thú, Linh Thú...)
        level: number;
        potential_grade: 'F' | 'E' | 'D' | 'C' | 'B' | 'A' | 'S' | 'SS' | 'SSS';
        potential_modifier: number; // Hệ số nhân sức mạnh (PM)

        // [UPDATED] 9 Chỉ số cơ bản đồng bộ (HP/MP là chỉ số Max/Base)
        stats: { HP: number; MP: number; STR: number; CON: number; AGI: number; DEF: number; SPI: number; INT: number; BLD: number; };
        stamina: { current: number; max: number; };

        health_current: number; // Giá trị máu hiện tại
        mp_current: number; // [NEW] Năng lượng tiêu hao hiện tại

        // [NEW] Gen Di Truyền (Genetics)
        genetics: {
            dominant_genes: string[];
            recessive_genes: string[];
            mutation_chance: number;
            genetic_stability: number; // 0-100%
        };

        // [NEW] Biến thăng cấp (Nấc Thang Sinh Mệnh)
        bloodline_energy_current: number; // Tích lũy năng lượng huyết mạch
        bloodline_energy_max: number; // Ngưỡng đột phá
        foundation_index: number; // Chỉ số Căn Cơ (CCI: 1.0 -> 1.5)

        breeding_status: string;
        mutation_traits: string[];
        evolution_paths: string[];

        // [NEW] Kho đồ riêng & Slot trang bị chuyên biệt của Thú
        inventory: Array<{ uid: string; name: string; type: string; rank_quality: string; stats_modifiers: object; description: string }>;

        equipment_slots: { 
            head: object | null; 
            body: object | null; 
            claw_weapon: object | null; 
            core: object | null; 
            accessory_1: object | null; 
            accessory_2: object | null; 
        };

        // Alias cũ (Giữ tương thích)
        beast_gear: Array<{ name: string; type: string; rank_quality: string; durability: number; description: string; }>;

        // [NEW] Trạng thái chiến đấu
        combat_modifiers: { 
            bloodline_activation_state: boolean; 
            environmental_adaptation: number; 
            active_buffs_debuffs: string[]; 
        };

        // [UPDATED] Kỹ năng chi tiết (SkillStructure v2)
        beast_skills: Array<{
          uid: string;
          name: string;
          rank_quality: string;
          description: string;
          cost: { type: string; value: number };
          cooldown: { value: number; unit: string }; // VD: {value: 3, unit: "Lượt"}
          cast_time: { value: number; unit: string; is_instant: boolean };
          elements: string[];
          range_type: string;
          interruptible: boolean;
          combo_tag: string;
        }>;

        soul_load_cost: number;
        loyalty: number; // 0-100
        intimacy: number;
        hunger: number;
        bloodline_purity: number;
        status_effects: string[];
      }
    check:
      - [CƠ CHẾ THÊM MỚI]: Để thu phục thêm thú mới, BẮT BUỘC dùng lệnh 'add' với path là "/beast_roster/-".
      - [CẤU TRÚC KỸ NĂNG]: Cấm xuất thiếu key trong mảng 'beast_skills'. Phải đầy đủ cost, cooldown (object), cast_time (object) để UI hiển thị đúng.
      - [GENETICS]: Khi lai tạo hoặc bắt thú hoang, phải khởi tạo 'genetics' với độ ổn định gen hợp lý (Thú hoang thường thấp hơn thú nuôi từ bé).

  # =================================================================
  # [2] NPC NHÂN LOẠI / Á NHÂN (Thợ săn, Học viên, Kẻ thù...)
  # =================================================================
  world_state.active_humanoid_npcs.{Index}:
    type: |-
      {
        name: string;
        race: string; // VD: "Nhân Loại", "Á Nhân"
        gender: 'Nam' | 'Nữ' | 'Không xác định';
        status: string; // Trạng thái (Bình thường, Trọng thương...)
        attitude: string; // Thái độ (Đề phòng, Thù địch, Bằng hữu...)
        spirit_rank: string; // Cảnh giới (Phàm Nhân, Hắc Thiết...)

        // [NEW] Biến Tu Vi & Căn Cơ NPC
        spirit_power_current: number;
        spirit_power_max: number;

        // [NEW] Thuộc tính Tinh Thần Lực
        spirit_affinity: { 
          base_elements: Array<{type: string, description: string, dominance: number}>; 
          combined_effect: {name: string, description: string, stability: number}; 
          weaknesses: string[]; 
        };

        // [NEW] Hệ thống Công Pháp NPC
        cultivation: {
          main_slot: { name: string; rank_quality: string; mastery_level: number; effect: string; };
          support_slots: Array<{ name: string; effect: string; }>;
        };

        // [UPDATED] 9 Chỉ số đồng bộ cho NPC + Luck
        stats: { HP: number; MP: number; STR: number; CON: number; AGI: number; DEF: number; SPI: number; INT: number; BLD: number; luck: number; };

        // [UPDATED] Slot Trang bị chi tiết (ItemSchema Object)
        equipment_slots: { 
            head: object | null; 
            body: object | null; 
            legs: object | null; 
            gloves: object | null; 
            shoes: object | null; 
            main_weapon: object | null; 
            sub_weapon: object | null; 
            necklace: object | null; 
            ring_1: object | null; 
            ring_2: object | null; 
        };

        // [NEW] Trạng thái chiến đấu cho NPC
        combat_modifiers: { 
            realm_suppression_modifier: number; 
            elemental_advantage_modifier: number; 
            tactical_command_level: number; 
            life_resonance_active: boolean; 
            environmental_adaptation: number;
            active_buffs_debuffs: string[]; 
        };

        skills: Array<object>; // SkillStructure đầy đủ
        hidden_motive: string; // Động cơ ẩn/Âm mưu (VD: "Muốn cướp thú của Ký chủ")
        trade_inventory: Array<object>; // Đồ mang theo người (ItemSchema)

        // Sủng thú của NPC (Cấu trúc rút gọn hoặc đầy đủ)
        tamed_beasts: Array<{
          beast_name: string;
          species: string;
          rank: string;
          health_status: string;
        }>;
      }
    check:
      - [XUẤT HIỆN]: Khi NPC bước vào cảnh, dùng lệnh 'add' vào path "/world_state/active_humanoid_npcs/-".
      - [RỜI ĐI/CHẾT]: Khi NPC biến mất hoặc chết, dùng lệnh 'remove' với Index tương ứng.
      - [EQUIPMENT]: NPC phải có trang bị (ít nhất là quần áo cơ bản) trong 'equipment_slots'. Khi chết, các item này sẽ rơi ra (lootable).

  # =================================================================
  # [3] NPC DỊ THÚ HOANG DÃ (Quái vật đối đầu)
  # =================================================================
  world_state.active_beast_npcs.{Index}:
    type: |-
      {
        name: string | null; // Có thể null nếu chưa có tên
        species: string; // VD: "Bạo Thủy Kình"

        // [NEW V5] Thông tin chủng tộc
        species_info: { name: string; type_class: string; description_lore: string; biological_features: string[] };
        bloodline_info: { name: string; description_lore: string; rank_quality: string; stats_modifiers: object };

        rank_tier: string;
        level: number;
        health_status: string; // VD: "100% HP", "Đứt lìa tay"

        // [NEW] Hệ thống Đa Hệ
        elemental_affinity: { base_elements: Array<{type: string}>; combined_effect: object; weaknesses: string[] };

        // [NEW] HP/MP thực tế để tính toán combat
        hp_current: number;
        mp_current: number;

        aggro_state: 'Passive' | 'Aggressive' | 'Fleeing'; // Trạng thái thù hận
        corruption_status: number; // Tỉ lệ ô nhiễm (0-100)
        territory: string; // Tập tính (Di cư, Săn mồi bầy đàn...)
        intelligence_level: string; // VD: "Thấp", "Cao", "Yêu Quái"

        // [UPDATED] 9 Chỉ số Dị thú hoang dã
        stats: { HP: number; MP: number; STR: number; CON: number; AGI: number; DEF: number; SPI: number; INT: number; BLD: number; };

        // [NEW] Biến thăng cấp & Căn cơ (Dành cho Quái có tiềm năng)
        bloodline_energy_current: number;
        bloodline_energy_max: number;
        foundation_index: number;

        // [NEW] Trang bị chuyên biệt cho Dị Thú (Nếu là quái có trí tuệ biết mặc giáp)
        equipment_slots: { head: object; body: object; claw_weapon: object; core: object; accessory_1: object; accessory_2: object; };

        // [NEW] Trạng thái chiến đấu cho Quái
        combat_modifiers: { 
            realm_suppression_modifier: number; 
            elemental_advantage_modifier: number; 
            bloodline_activation_state: boolean; 
            environmental_adaptation: number; 
            active_buffs_debuffs: string[]; 
        };

        innate_skills: Array<object>; // SkillStructure
        loot_table: Array<object>; // ItemSchema (Sẽ rớt ra vật phẩm/Lõi gì nếu bị giết)
      }
    check:
      - [GIAO TRANH]: Khi Ký chủ gặp Dị thú hoang dã, lập tức 'add' thông tin chúng vào mảng này.
      - [PHẦN THƯỞNG]: Bắt buộc điền 'loot_table' với đầy đủ UID và Stats. Nếu quái bị tiêu diệt, AI phải chuyển đồ từ 'loot_table' sang 'inventory' của Ký chủ bằng lệnh 'add' hoặc 'move'.

